import { HttpClient } from '@angular/common/http';
import { Injectable } from '@angular/core';
import { Observable } from 'rxjs';
import { ITradePair } from 'src/app/trade/models/trade-pair.model';
import { IAPIResponse } from 'src/app/shared/models/api-response.model';
import { environment } from 'src/environments/environment';


@Injectable({
  providedIn: 'root',
})
export class SignupService {
  constructor(private http: HttpClient) { }

  createUser(name: string, surname: string, email: string): Observable<IAPIResponse> {
    let selectedTradingPairs: ITradePair[] = [];
    let riskAppetite: number = 5;

    const selectedTradingPairsFromStorage = sessionStorage.getItem('selectedTradingPairs');
    const riskAppetiteFromStorage = sessionStorage.getItem('riskAppetite');

    if (selectedTradingPairsFromStorage !== null) {
      selectedTradingPairs = JSON.parse(selectedTradingPairsFromStorage);
    }

    if (riskAppetiteFromStorage !== null) {
      riskAppetite = JSON.parse(riskAppetiteFromStorage);
    }

    const selectedTradingPairIDs: number[] = selectedTradingPairs.map(tradePair => tradePair.id);

    const userObject = {
      name: name,
      surname: surname,
      email: email,
      risk: riskAppetite,
      trading_pair_ids: selectedTradingPairIDs
    };

    return this.http.post<IAPIResponse>(`${environment.apiUrl}/user/`, userObject);
  }

  getUser(): Observable<IAPIResponse> {
    return this.http.get<IAPIResponse>(`${environment.apiUrl}/user/`);
  }


  storeItem(key: string, data: any): void {
    sessionStorage.setItem(key, JSON.stringify(data));
  }

  getItem(key: string): number | ITradePair[] {
    const data = sessionStorage.getItem(key);
    return data ? JSON.parse(data) : null;
  }
}
