import { Injectable } from '@angular/core';
import { IUser, IUserPutDto } from '../models/user.model';
import { Observable, map } from 'rxjs';
import { HttpClient } from '@angular/common/http';
import { IAPIResponse } from 'src/app/shared/models/api-response.model';
import { environment } from 'src/environments/environment';

@Injectable({
  providedIn: 'root',
})
export class UserService {
  private _user: IUser = {
    riskAppetiteScore: 5,
    enableNotifications: true,
  };

  constructor(private http: HttpClient) { }


  getUser(): Observable<IUser> {
    return this.http.get<IAPIResponse>(`${environment.apiUrl}/user`).pipe(
      map((response: IAPIResponse) => {
        if (response.success) {
          this._user = {
            ...this._user,
            riskAppetiteScore: response.records[0].risk,
            enableNotifications: true,
          };
          return this._user;
        } else {
          throw new Error('User not found');
        }
      })
    );
  }

  updateUser(user: IUserPutDto): Observable<IUser> {
    const body = {
      risk: user.riskAppetiteScore
    };

    return this.http.put<any>(`${environment.apiUrl}/user`, body).pipe(
      map((response: IAPIResponse) => {
        if (response && response.records && response.records.length > 0 && 'risk' in response.records[0]) {
          return {
            riskAppetiteScore: response.records[0].risk,
            enableNotifications: true
          };
        } else {
          throw new Error('Unexpected API response format');
        }
      }),
    );
  }


}
