import { Component, EventEmitter, Input, Output } from '@angular/core';
import { ITradePair } from 'src/app/trade/models/trade-pair.model';
import { Utils } from 'src/app/util/util';

export interface ISearchResult extends ITradePair {
  selected: boolean;
}

@Component({
  selector: 'app-results',
  templateUrl: './results.component.html',
  styleUrls: ['./results.component.scss'],
})
export class ResultsComponent {

 _results!: ISearchResult[];
  @Input() set results(results: ITradePair[]) {
    if (!results) return;
    this._results = Utils.copy(results).map((result) => {
      return { ...result, selected: false };
    });
  }
  get results(): ISearchResult[] {
    return this._results;
  }

  @Output() selected: EventEmitter<ISearchResult[]> = new EventEmitter();

  select(item: ISearchResult): void {
    item.selected = !item.selected;

    this.selected.emit(
      Utils.copy(this.results).filter((result) => result.selected)
    );
  }

  navigateToSuggestions(): void {
    setTimeout(()=>{
      location.reload();
    }, 100);
  }
}
