import { AfterViewInit, Component, ViewChild } from '@angular/core';
import { MatDrawer } from '@angular/material/sidenav';
import { Select, Store } from '@ngxs/store';
import { Observable } from 'rxjs';
import { AppState } from './store/app.state';
import { UntilDestroy, untilDestroyed } from '@ngneat/until-destroy';
import { SetSidenavState } from './store/app.actions';
import { NavigationEnd, Router } from '@angular/router';
import { CookieService } from 'ngx-cookie-service';
import { Subscription } from 'rxjs';
import { CookieExtensionService } from './shared/services/cookie-extension.service';

declare const gtag: Function;

@UntilDestroy()
@Component({
  selector: 'app-root',
  templateUrl: './app.component.html',
  styleUrls: ['./app.component.scss'],
})
export class AppComponent implements AfterViewInit {
  @ViewChild('drawer') drawer!: MatDrawer;
  @Select(AppState.sidenavState) sidenavState$!: Observable<boolean>;
  private cookieSubscription!: Subscription;
  title = 'marketraker';
  showCookiePopup: boolean = false;

  constructor(private store: Store, public router: Router, private cookieExtensionService: CookieExtensionService) {
    this.router.events.subscribe((event) => {
      if (event instanceof NavigationEnd) {
        gtag('config', 'G-1HW1G90CDH', { 'page_path': event.urlAfterRedirects });
      }
    })

  }

  ngOnInit(): void {
    this.subscribeToCookieStatus();
  }


  ngOnDestroy(): void {
    this.cookieSubscription.unsubscribe();
  }

  ngAfterViewInit(): void {
    this.subscribeToSidenavState();
    this.subscribeToDrawerEvent();
  }

  private subscribeToSidenavState(): void {
    this.sidenavState$.pipe(untilDestroyed(this)).subscribe((state) => {
      if (!this.drawer) return;
      if (state === true) {
        this.drawer.open();
      } else {
        this.drawer.close();
      }
    });
  }

  private subscribeToCookieStatus(): void {
    this.cookieExtensionService.shouldDisplayCookies$.pipe(untilDestroyed(this)).subscribe(shouldDisplayCookies => {
      this.showCookiePopup = shouldDisplayCookies;
    });
  }

  private subscribeToDrawerEvent(): void {
    this.drawer.openedChange.pipe(untilDestroyed(this)).subscribe((state) => {
      this.store.dispatch(new SetSidenavState(state));
    });
  }

}
