import { Component, Input, ChangeDetectorRef, ViewChild } from '@angular/core';
import { Utils } from 'src/app/util/util';
import { ITradePairNotification } from '../../models/trade-pair-subscription-info.model';
import { TradeService } from '../../services/trade.service';
import { ConfirmationModalComponent } from '../confirmation-modal/confirmation-modal.component';

@Component({
  selector: 'app-notification-card',
  templateUrl: './notification-card.component.html',
  styleUrls: ['./notification-card.component.scss'],
})
export class NotificationCardComponent {
  private _tradingPair!: ITradePairNotification;
  @Input() set tradingPair(value: ITradePairNotification) {
    this._tradingPair = {
      ...Utils.copy(value),
    };

  }

  constructor(
    private cdr: ChangeDetectorRef,
    private tradeService: TradeService
  ) { }


  get tradingPair(): ITradePairNotification {
    return this._tradingPair;
  }

  get longNotifications(): boolean {
    return this.tradingPair.tradingType === 'Long' || this.tradingPair.tradingType === 'Short/Long';
  }

  set longNotifications(value: boolean) {
    if (value) {
      this.tradingPair.tradingType = this.tradingPair.tradingType === 'Short' ? 'Short/Long' : 'Long';
    } else {
      this.tradingPair.tradingType = this.tradingPair.tradingType === 'Short/Long' ? 'Short' : 'Short';
    }
  }

  get shortNotifications(): boolean {
    return this.tradingPair.tradingType === 'Short' || this.tradingPair.tradingType === 'Short/Long';
  }

  set shortNotifications(value: boolean) {
    if (value) {
      this.tradingPair.tradingType = this.tradingPair.tradingType === 'Long' ? 'Short/Long' : 'Short';
    } else {
      this.tradingPair.tradingType = this.tradingPair.tradingType === 'Short/Long' ? 'Long' : 'Long';
    }
  }

  toggle(): void {
    this.tradingPair.expanded = !this.tradingPair.expanded;
  }

  @ViewChild(ConfirmationModalComponent) modalComponent!: ConfirmationModalComponent;
  showModal = false;

  openModal(): void {
    this.showModal = true;
  }

  closeModal(): void {
    this.showModal = false;
  }

  remove(): void {
    // Convert ITradePairNotification to ITradePair for compatibility with TradeService
    let tradePair = {
      id: this.tradingPair.tradingPairID,
      name: this.tradingPair.tradingPairName,
      unit: '',
      logo: this.tradingPair.icon,
      active: true,
      overview: '',
      staffRecommended: false,
      externalChartURL: '',
      category: "Stocks" as "Stocks" | "Funds" | "Futures" | "Forex" | "Crypto" | "Indices" | "Bonds" | "Economy",
    };


    this.tradeService.removeFromWatchList(tradePair)
      .subscribe();
    
    this.closeModal();
    setTimeout(()=>{
      location.reload();
    }, 300);
  }


  update(): void {
    this.tradeService.updateTradingPairNotification(this.tradingPair)
      .subscribe();
  }

}
