import { Component, OnInit } from '@angular/core';
import { Router, NavigationEnd, ActivatedRoute } from '@angular/router';

@Component({
  selector: 'app-layout',
  templateUrl: './layout.component.html',
  styleUrls: ['./layout.component.scss'],
})
export class LayoutComponent implements OnInit {
  isSettingsRoute: boolean = false;

  constructor(private router: Router, private route: ActivatedRoute) {}

  ngOnInit() {
    this.router.events.subscribe((event) => {
      if (event instanceof NavigationEnd) {
        this.isSettingsRoute = this.router.url === '/trade/settings';
      }
    });

    this.isSettingsRoute = this.router.url === '/trade/settings' || this.route.snapshot?.routeConfig?.path === 'trade/settings';
  }

  isSpecificComponent(): boolean {
    const currentRoute = this.router.routerState.snapshot.url;
    const connectWalletRoute = '/trade/connect-wallet';
    const insufficientTokensRoute = '/trade/insufficient-tokens';

    return currentRoute === connectWalletRoute || currentRoute === insufficientTokensRoute;
  }
}
