import { NgModule } from '@angular/core';
import { RouterModule, Routes } from '@angular/router';
import { LayoutComponent } from './components/layout/layout.component';
import { IndicatorsComponent } from './components/indicators/indicators.component';
import { SettingsComponent } from './components/settings/settings.component';
import { ConnectWalletComponent } from './components/connect-wallet/connect-wallet.component';
import { InsufficientTokensComponent } from './components/insufficient-tokens/insufficient-tokens.component';
import { AuthGuard } from '../auth/guards/auth.guard';

const routes: Routes = [
  {
    path: '',
    component: LayoutComponent,
    children: [
      { path: 'connect-wallet', component: ConnectWalletComponent, canActivate: [AuthGuard] },
      { path: 'insufficient-tokens', component: InsufficientTokensComponent, canActivate: [AuthGuard] },
      { path: 'indicators', component: IndicatorsComponent, canActivate: [AuthGuard] },
      { path: 'settings', component: SettingsComponent, canActivate: [AuthGuard] },
      { path: '', redirectTo: 'indicators', pathMatch: 'full' },
    ],
  },
];

@NgModule({
  imports: [RouterModule.forChild(routes)],
  exports: [RouterModule],
})
export class TradeRoutingModule { }
