import { Injectable } from '@angular/core';
import { Action, Selector, State, StateContext } from '@ngxs/store';
import {
  UpdateRiskAppetite,
  UpdateSelectedTradingPairs,
} from './registration.actions';
import { ITradePair } from 'src/app/trade/models/trade-pair.model';
import { SignupService } from '../services/signup.service';

interface RegistrationStateModel {
  riskAppetite: number;
  selectedTradingPairs: ITradePair[];
}

@Injectable()
@State<RegistrationStateModel>({
  name: 'riskAppetite',
  defaults: {
    riskAppetite: 5,
    selectedTradingPairs: [],
  },
})
export class RegistrationState {
  constructor(private signupService: SignupService) { }


  @Selector()
  static riskAppetite(state: RegistrationStateModel): number {
    return state.riskAppetite;
  }

  @Selector()
  static selectedTradingPairs(state: RegistrationStateModel): ITradePair[] {
    return state.selectedTradingPairs;
  }

  @Action(UpdateRiskAppetite)
  updateRiskAppetite(
    { patchState, getState }: StateContext<RegistrationStateModel>,
    { riskAppetite }: UpdateRiskAppetite
  ): void {
    patchState({ riskAppetite });
    const state = getState();
    this.signupService.storeItem('riskAppetite', state.riskAppetite);
  }

  @Action(UpdateSelectedTradingPairs)
  toggleTradingPair(
    { patchState, getState }: StateContext<RegistrationStateModel>,
    { selected }: UpdateSelectedTradingPairs
  ): void {
    patchState({ selectedTradingPairs: selected });
    const state = getState();
    this.signupService.storeItem('selectedTradingPairs', state.selectedTradingPairs);
  }
}
