import { Injectable } from '@angular/core';
import { Action, Selector, State, StateContext } from '@ngxs/store';
import { SetSidenavState, ToggleSidenavState } from './app.actions';

export interface IAppStateModel {
  sidenavOpen: boolean;
}

@Injectable()
@State<IAppStateModel>({
  name: 'app',
  defaults: {
    sidenavOpen: false,
  },
})
export class AppState {
  @Selector()
  static sidenavState(state: IAppStateModel): boolean {
    return state.sidenavOpen;
  }

  @Action(SetSidenavState) updateSidenavState(
    { patchState }: StateContext<IAppStateModel>,
    { state }: SetSidenavState
  ): void {
    patchState({ sidenavOpen: state });
  }

  @Action(ToggleSidenavState) toggleSidenavState({
    patchState,
    getState,
  }: StateContext<IAppStateModel>): void {
    patchState({ sidenavOpen: !getState().sidenavOpen });
  }
}
