import { Component } from '@angular/core';
import { UserService } from '../../services/user.service';
import { IUser, IUserPutDto } from '../../models/user.model';
import { UntilDestroy, untilDestroyed } from '@ngneat/until-destroy';
import { ToastrService } from 'ngx-toastr';
import { Store } from '@ngxs/store';
import { UserState } from '../../store/user.state';
import { UpdateUser } from '../../store/user.actions';

@UntilDestroy()
@Component({
  selector: 'app-settings-save',
  templateUrl: './settings-save.component.html',
  styleUrls: ['./settings-save.component.scss']
})
export class SettingsSaveComponent {
  loading = false;
  user: IUser = {
    riskAppetiteScore: 5,
    enableNotifications: true
  };
  isChecked = false;

  constructor(
    private userService: UserService,
    private toastr: ToastrService,
    private store: Store
  ) { }

  ngOnInit(): void {
    this.user = { ...this.store.selectSnapshot(UserState.user) };
  }

  toggleNotifications(): void {
    const updatedUser: IUser = {
      ...this.user,
      enableNotifications: !this.user.enableNotifications
    };

    this.isChecked = !this.isChecked;
    this.store.dispatch(new UpdateUser(updatedUser));
  }

  save(): void {
    this.loading = true;
    const user: IUser = this.store.selectSnapshot(UserState.user);
    const userUpdate: IUserPutDto = {
      riskAppetiteScore: user.riskAppetiteScore
    }
    if (userUpdate) {
      this.userService
        .updateUser(userUpdate)
        .pipe(untilDestroyed(this))
        .subscribe({
          next: () => {
            this.loading = false;
            this.toastr.success('Profile updated successfully');
          },
          error: (error) => {
            this.loading = false;
            this.toastr.error('Failed to update profile');
            console.error(error);
          }
        });
    }
  }
}
