import {
  AfterContentChecked,
  AfterContentInit,
  AfterViewInit,
  Component,
  ElementRef,
  EventEmitter,
  HostBinding,
  HostListener,
  Input,
  Output,
  ViewChild,
} from '@angular/core';
import { Utils } from 'src/app/util/util';

export interface IScrollListItem {
  img: string;
  title: string;
  subtitle: string;
}

@Component({
  selector: 'app-scroll-list',
  templateUrl: './scroll-list.component.html',
  styleUrls: ['./scroll-list.component.scss'],
})
export class ScrollListComponent implements AfterContentChecked, AfterViewInit {
  private MIN_GAP = 8;
  private ITEMS_TO_SCROLL = 3;
  private gap = 0;
  private itemWidth = 0;

  @ViewChild('list') list: ElementRef<HTMLDivElement> | undefined;

  @Input() set itemsToScroll(value: number) {
    if (value) this.ITEMS_TO_SCROLL = value;
  }

  _items: IScrollListItem[] = [];
  @Input() set items(items: any[]) {
    if (!items) return;
    this._items = Utils.copy(items);
  }
  get items(): IScrollListItem[] {
    return this._items;
  }

  @Output() selected: EventEmitter<IScrollListItem> = new EventEmitter();

  ngAfterContentChecked(): void {
    this.setListWidth();
  }

  ngAfterViewInit(): void {
    this.allowListHorizontalScroll();
  }

  private allowListHorizontalScroll(): void {
    if (!this.list || !this.list.nativeElement.parentElement) return;
    this.list.nativeElement.parentElement.addEventListener('wheel', (e) => {
      if (!this.list || !this.list.nativeElement.parentElement) return;
      e.preventDefault();
      if (e.deltaY < 0) {
        this.list.nativeElement.parentElement.scrollLeft -= this.itemWidth;
      } else {
        this.list.nativeElement.parentElement.scrollLeft += this.itemWidth;
      }
    });
  }

  @HostListener('window:resize', ['$event'])
  private setListWidth() {
    if (!this.list || this.list?.nativeElement?.children?.length === 0) return;
    // get list parent width
    const parent = this.list.nativeElement.parentElement;
    const parentWidth = parent?.getBoundingClientRect().width || 0;

    // get first child item width
    const firstChild = this.list.nativeElement.children[0];
    const firstChildWidth = firstChild.getBoundingClientRect().width;
    this.itemWidth = firstChildWidth;

    // get amount of items that can fit in parent
    let itemsThatFit = Math.floor(parentWidth / firstChildWidth);

    // get remaining space and calculate gap size
    let remainingSpace = parentWidth - itemsThatFit * firstChildWidth;
    let gap = remainingSpace / (itemsThatFit - 1);

    // if gap is too small, reduce amount of items that fit
    while (gap < this.MIN_GAP) {
      itemsThatFit--;
      remainingSpace = parentWidth - itemsThatFit * firstChildWidth;
      gap = remainingSpace / (itemsThatFit - 1);
    }
    this.gap = gap;
    if (this.gap === Infinity) this.gap = this.MIN_GAP;

    // set gap and width
    this.list.nativeElement.style.gap = `${gap}px`;
    this.list.nativeElement.style.width = `${
      this.list.nativeElement.children.length * firstChildWidth +
      (this.list.nativeElement.children.length - 1) * gap
    }px`;
  }

  select(item: IScrollListItem): void {
    this.selected.emit(item);
  }

  next() {
    if (!this.list || !this.list.nativeElement.parentElement) return;
    this.list.nativeElement.parentElement.scrollLeft +=
      this.ITEMS_TO_SCROLL * this.itemWidth + this.ITEMS_TO_SCROLL * this.gap;
  }

  prev() {
    if (!this.list || !this.list.nativeElement.parentElement) return;
    this.list.nativeElement.parentElement.scrollLeft -=
      this.ITEMS_TO_SCROLL * this.itemWidth + this.ITEMS_TO_SCROLL * this.gap;
  }
}
