import { Component, HostBinding } from '@angular/core';
import { Store, Select } from '@ngxs/store';
import { UpdateRiskAppetite } from '../../store/registration.actions';
import { Observable } from 'rxjs';
import { RegistrationState } from '../../store/registration.state';
import { UntilDestroy, untilDestroyed } from '@ngneat/until-destroy';

@UntilDestroy()
@Component({
  selector: 'app-signup-risk',
  templateUrl: './signup-risk.component.html',
  styleUrls: ['./signup-risk.component.scss'],
})
export class SignupRiskComponent {
  @HostBinding('class') layoutCls = 'registration-layout';
  @Select(RegistrationState.riskAppetite) riskAppetite$!: Observable<number>;
  riskAppetiteScore: number = 0;

  constructor(private store: Store) { }

  ngOnInit(): void {
    this.subscribeToRiskAppetite();
  }

  private subscribeToRiskAppetite(): void {
    this.riskAppetite$
      .pipe(untilDestroyed(this))
      .subscribe((appetite) => (this.riskAppetiteScore = appetite));
  }

  updateRiskAppetiteScore(score: number): void {
    this.store.dispatch(new UpdateRiskAppetite(score));
  }
}
