import { Injectable } from '@angular/core';
import { AuthService } from '@auth0/auth0-angular';
import { CookieService } from 'ngx-cookie-service';
import { CookieExtensionService } from './cookie-extension.service';
@Injectable({
    providedIn: 'root'
})

export class Auth0ExtensionService {
    constructor(private authService: AuthService, private cookies: CookieExtensionService) { }

    loginWithRedirect(options: any): void {
        if (this.cookies.checkCookies()) {
            this.authService.loginWithRedirect(options)
        }
    }
}