import { APP_INITIALIZER, NgModule } from '@angular/core';
import { BrowserModule } from '@angular/platform-browser';
import { AuthModule } from './auth/auth.module';
import { HTTP_INTERCEPTORS } from '@angular/common/http';
import { AppRoutingModule } from './app-routing.module';
import { AppComponent } from './app.component';
import { BrowserAnimationsModule } from '@angular/platform-browser/animations';
import { AuthModule as Auth0Module } from '@auth0/auth0-angular';
import { SharedModule } from './shared/shared.module';
import { TradeModule } from './trade/trade.module';
import { NgxsModule } from '@ngxs/store';
import { TradeState } from './trade/store/trade.store';
import { DiscoveryModule } from './discovery/discovery.module';
import { IconService } from './shared/services/icon.service';
import { AppState } from './store/app.state';
import { RegistrationState } from './registration/store/registration.state';
import { ProfileModule } from './profile/profile.module';
import { ToastrModule } from 'ngx-toastr';
import { LocationStrategy, HashLocationStrategy } from '@angular/common';
import { Auth0InterceptorService } from './shared/services/auth0-interceptor.service';
import { environment } from '../environments/environment';
import { UserState } from './profile/store/user.state';




@NgModule({
  declarations: [AppComponent],
  imports: [
    BrowserModule,
    AppRoutingModule,
    BrowserAnimationsModule,
    AuthModule,
    Auth0Module.forRoot({
      domain: environment.auth0.domain,
      clientId: environment.auth0.clientId,
      authorizationParams: {
        redirect_uri: window.location.origin + '#' + environment.redirectURL,
        responseType: 'token id_token',
        audience: environment.auth0.audience
      },
      cacheLocation: 'localstorage',
    }),
    NgxsModule.forRoot([AppState, TradeState, RegistrationState, UserState], {
      developmentMode: true,
    }),
    ToastrModule.forRoot({
      timeOut: 7000,
      positionClass: 'toast-bottom-right',
      preventDuplicates: true,
    }),
    TradeModule,
    DiscoveryModule,
    ProfileModule,
    SharedModule,
  ],
  providers: [
    IconService,
    {
      provide: APP_INITIALIZER,
      useFactory: (service: IconService) =>
        function () {
          return service.customIcons();
        },
      deps: [IconService],
      multi: true,
    },
    { provide: LocationStrategy, useClass: HashLocationStrategy },
    { provide: HTTP_INTERCEPTORS, useClass: Auth0InterceptorService, multi: true },
  ],
  bootstrap: [AppComponent],
})
export class AppModule { }
