import { NgModule } from '@angular/core';
import { RouterModule, Routes } from '@angular/router';
import { LandingPageComponent } from './components/landing-page/landing-page.component';
import { SignupRiskComponent } from './components/signup-risk/signup-risk.component';
import { SignupTradingPairsComponent } from './components/signup-trading-pairs/signup-trading-pairs.component';
import { SignupDiscoverComponent } from './components/signup-discover/signup-discover.component';
import { SignupRegistrationComponent } from './components/signup-registration/signup-registration.component';
import { TradingPairsSelectedGuard } from './guards/trading-pairs-selected.guard';
import { LayoutComponent } from './components/layout/layout.component';
import { SignedOut } from '../auth/guards/signed-out';
import { SignUpComponent } from './components/sign-up/sign-up.component';

const routes: Routes = [
  {
    path: '',
    component: LayoutComponent,
    children: [
      { path: 'home', component: LandingPageComponent, canActivate: [SignedOut] },
      { path: '', redirectTo: 'signup-risk', pathMatch: 'full' },
      {
        path: '',
        component: SignUpComponent,
        children: [
          { path: 'risk-appetite', component: SignupRiskComponent, canActivate: [SignedOut] },
          { path: 'trading-pairs', component: SignupTradingPairsComponent, canActivate: [SignedOut] },
          {
            path: 'discover',
            component: SignupDiscoverComponent,
            canActivate: [TradingPairsSelectedGuard, SignedOut],
          },
          {
            path: 'register',
            component: SignupRegistrationComponent,
            canActivate: [TradingPairsSelectedGuard, SignedOut],
          },
        ],
      },
    ],
  },
];

@NgModule({
  imports: [RouterModule.forChild(routes)],
  exports: [RouterModule],
})
export class RegistrationRoutingModule { }
