import { Component } from '@angular/core';
import { CookieService } from 'ngx-cookie-service';
import { CookieExtensionService } from '../../services/cookie-extension.service';

@Component({
  selector: 'app-cookie-popup',
  templateUrl: './cookie-popup.component.html',
  styleUrls: ['./cookie-popup.component.scss']
})
export class CookiePopupComponent {

  constructor(private cookieExtensionService: CookieExtensionService) {
  }

  accept() {
    this.cookieExtensionService.accept()
  }

  decline() {
    this.cookieExtensionService.decline()
  }
}
