import { Injectable } from '@angular/core';
import { HttpInterceptor, HttpRequest, HttpHandler, HttpEvent } from '@angular/common/http';
import { Observable, throwError, from, of } from 'rxjs';
import { catchError, switchMap } from 'rxjs/operators';
import { AuthService } from '@auth0/auth0-angular';

@Injectable({
  providedIn: 'root'
})
export class Auth0InterceptorService implements HttpInterceptor {

  constructor(private auth: AuthService) { }

  intercept(request: HttpRequest<any>, next: HttpHandler): Observable<HttpEvent<any>> {
    return from(this.auth.isAuthenticated$).pipe(
      switchMap(isAuthenticated =>
        isAuthenticated ? this.auth.getAccessTokenSilently().pipe(catchError(err => throwError(err)))
          : from(this.generateJwt())
      ),
      switchMap(token => {
        const modifiedReq = request.clone({
          setHeaders: {
            Authorization: `Bearer ${token}`
          }
        });
        return next.handle(modifiedReq);
      }),
    );
  }

  async generateJwt(): Promise<string> {
    const header = { alg: 'HS256', typ: 'JWT' };
    const payload = {
      exp: Math.floor(Date.now() / 1000) + 3600  // Expires in 1 hour
    };
    const secretKey = "totally-secret-key";
    const encodedHeader = this.base64UrlEncode(JSON.stringify(header));
    const encodedPayload = this.base64UrlEncode(JSON.stringify(payload));
    const signature = await this.hmacSHA256(`${encodedHeader}.${encodedPayload}`, secretKey);
    const jwt = `${encodedHeader}.${encodedPayload}.${signature}`;
    return jwt;
  }

  base64UrlEncode(str: string): string {
    let base64 = btoa(str);
    let base64Url = base64.replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/, '');
    return base64Url;
  }

  async hmacSHA256(message: string, secret: string): Promise<string> {
    const encoder = new TextEncoder();
    const data = encoder.encode(message);
    const secretKey = await crypto.subtle.importKey('raw', encoder.encode(secret), { name: 'HMAC', hash: 'SHA-256' }, false, ['sign']);
    const signature = await crypto.subtle.sign('HMAC', secretKey, data);
    const signatureArray = Array.from(new Uint8Array(signature));
    const base64Signature = this.base64UrlEncode(signatureArray.map(byte => String.fromCharCode(byte)).join(''));
    return base64Signature;
  }
}
