import { Component, Input } from '@angular/core';
import { IIndicatorData } from '../../models/indicator-data.model';
import { format, isToday, isTomorrow, isYesterday } from 'date-fns';
import { ICategory } from '../../models/category.model';


@Component({
  selector: 'app-indicator',
  templateUrl: './indicator.component.html',
  styleUrls: ['./indicator.component.scss']
})
export class IndicatorComponent {
  @Input() data: IIndicatorData = {
    tradingPair: 'ETH/USDT',
    leverage: 1,
    action: 'Short',
    entryPrice: 4800,
    exitPrice: 4100,
    time: new Date(),
    imgSrc: 'https://upload.wikimedia.org/wikipedia/commons/thumb/4/46/Bitcoin.svg/2048px-Bitcoin.svg.png',
  };
  isNew!: boolean;

  get displayTime(): string {
    const { time } = this.data;

    const timePart = format(time, 'HH:mm');
    const dateFormat = 'MMM d, yyyy';

    if (isToday(time)) {
      return `Today at ${timePart}`;
    } else if (isTomorrow(time)) {
      return `Tomorrow at ${timePart}`;
    } else if (isYesterday(time)) {
      return `Yesterday at ${timePart}`;
    }
    else {
      return `${format(time, dateFormat)} at ${timePart}`;
    }
  }

  get category(): ICategory {
    const now = new Date();

    if (
      this.data.time.getDate() === now.getDate() &&
      this.data.time.getMonth() === now.getMonth() &&
      this.data.time.getFullYear() === now.getFullYear()
    ) {
      return 'today';
    } else if (this.data.time > now) {
      return 'coming-up';
    } else {
      return 'history';
    }
  }

  getTextColorClass(): string {
    if (this.data.action === 'Short') {
      return 'short-text';
    } else if (this.data.action === 'Long') {
      return 'long-text';
    } else {
      return '';
    }
  }

  get leftImageSrc(): string {
    if (this.data.action === 'Short') {
      return '../../../assets/images/sell_tag.png';
    } else if (this.data.action === 'Long') {
      return '../../../assets/images/buy_tag.png';
    } else {
      return '';
    }
  }

  get rightImageSrc(): string {
    if (this.data.action === 'Short') {
      return '../../../assets/images/bear.svg';
    } else if (this.data.action === 'Long') {
      return '../../../assets/images/bull.svg';
    } else {
      return '';
    }
  }

}
