import {
  AfterContentChecked,
  AfterViewInit,
  Component,
  ElementRef,
  HostBinding,
  HostListener,
  OnInit,
  ViewChild,
} from '@angular/core';
import { SignupService } from '../../services/signup.service';
import { UntilDestroy, untilDestroyed } from '@ngneat/until-destroy';
import { Store, Select } from '@ngxs/store';
import { RegistrationState } from '../../store/registration.state';
import { Observable } from 'rxjs';
import { ITradePairCard } from 'src/app/shared/components/trade-pair-card/trade-pair-card.component';
import { Utils } from 'src/app/util/util';
import { ITradePair } from 'src/app/trade/models/trade-pair.model';
import { TradeService } from 'src/app/trade/services/trade.service';
import { UpdateSelectedTradingPairs } from '../../store/registration.actions';

interface TradingPair {
  name: string;
  overview: string;
  unit: string;
  img_src: string;
}

@UntilDestroy()
@Component({
  selector: 'app-signup-trading-pairs',
  templateUrl: './signup-trading-pairs.component.html',
  styleUrls: ['./signup-trading-pairs.component.scss'],
})
export class SignupTradingPairsComponent
  implements OnInit, AfterContentChecked {
  @HostBinding('class') layoutCls = 'registration-layout';
  @ViewChild('carousel') carousel!: ElementRef<HTMLDivElement>;

  private _tradePairs: ITradePair[] = [];
  cards!: ITradePairCard[];
  cardGroups: any[][] = [];

  // check if the user has selected cards
  get hasSelectedCards(): boolean {
    if (!this.cards) return false;
    return this.cards?.some((card) => card.selected);
  }

  constructor(private tradeService: TradeService, private store: Store) { }

  ngOnInit(): void {
    this.subscribeToTradingPairs();
  }
  ngAfterContentChecked(): void {
    this.setCarouselSize();
  }

  @HostListener('window:resize', ['$event'])
  setCarouselSize(): void {
    if (!this.carousel) return;

    // get the carousel element
    const carousel = this.carousel.nativeElement;
    // get the parent element
    const parent = carousel.parentElement;
    // get the children of the carousel
    const children = carousel.children;

    if (!parent || !children) return;

    // get the width of the parent
    const parentWidth = parent.offsetWidth;

    // set the width of the carousel
    carousel.style.width = `${parentWidth}px`;
    // set the width of the children
    for (let i = 0; i < children.length; i++) {
      const child = children[i] as HTMLElement;
      child.style.width = `${parentWidth}px`;
      child.style.flex = `0 0 ${parentWidth}px`;
    }
  }

  private subscribeToTradingPairs(): void {
    this.tradeService
      .getRecommendedTradingPairs()
      .pipe(untilDestroyed(this))
      .subscribe((response) => {
        this._tradePairs = Utils.copy(response);
        this.cards = Utils.copy(response).map((card) => {
          return { ...card, selected: false };
        });

        this.checkStoreForSelectedPairs();

        this.cardGroups = this.chunkArray(this.cards, 8);
      });
  }


  private updateStore(): void {
    // map the selected cards to the trading pairs
    const selectedTradePairs = this._tradePairs.filter((pair) => {
      return this.cards.find((card) => card.id === pair.id)?.selected;
    });
    this.store.dispatch(new UpdateSelectedTradingPairs(selectedTradePairs));
  }

  private checkStoreForSelectedPairs(): void {
    this.store
      .select(RegistrationState.selectedTradingPairs)
      .pipe(untilDestroyed(this))
      .subscribe((selectedPairsInStore) => {
        if (selectedPairsInStore.length > 0) {
          this.cards.forEach((card) => {
            const isSelectedInStore = selectedPairsInStore.some(
              (storePair) => storePair.id === card.id
            );
            if (isSelectedInStore) {
              card.selected = true;
            }
          });
        }
      });
  }

  select(item: any): void {
    item.selected = !item.selected;

    this.updateStore();
  }

  chunkArray(array: any[], chunkSize: number): any[][] {
    return Array(Math.ceil(array.length / chunkSize))
      .fill(undefined)
      .map((_, i) => array.slice(i * chunkSize, i * chunkSize + chunkSize));
  }

  onPrevClick() {
    const carouselWrapper = document.querySelector(
      '.carousel-wrapper'
    ) as HTMLElement;
    const carouselSlide = document.querySelector(
      '.carousel-slide'
    ) as HTMLElement;
    const slideWidth = carouselSlide.offsetWidth;
    const currentScrollLeft = carouselWrapper.scrollLeft;
    carouselWrapper.scrollTo({
      left: currentScrollLeft - slideWidth,
      behavior: 'smooth',
    });
  }

  onNextClick() {
    const wrapper = document.querySelector('.carousel-wrapper') as HTMLElement;
    const slide = wrapper.querySelector('.carousel-slide') as HTMLElement;
    const slideWidth = slide.offsetWidth;
    const currentScroll = wrapper.scrollLeft;
    const nextScroll = currentScroll + slideWidth;
    wrapper.scrollTo({ left: nextScroll, behavior: 'smooth' });
  }
}
