import { Component, OnInit } from '@angular/core';
import { ITradePair } from '../../models/trade-pair.model';
import { Select } from '@ngxs/store';
import { TradeState } from '../../store/trade.store';
import { TradeService } from '../../services/trade.service';
import { Observable } from 'rxjs';
import { UntilDestroy, untilDestroyed } from '@ngneat/until-destroy';
import { ITradePairNotification } from '../../models/trade-pair-subscription-info.model';
import { combineLatest } from 'rxjs';
import { map } from 'rxjs/operators';

@UntilDestroy()
@Component({
  selector: 'app-settings',
  templateUrl: './settings.component.html',
  styleUrls: ['./settings.component.scss'],
})
export class SettingsComponent implements OnInit {
  @Select(TradeState.selectedTradingPairs) selectedTradingPairs$!: Observable<
    ITradePair[]
  >;
  tradingPairNotifications: ITradePairNotification[] = [];
  tradePairs: ITradePair[] = [];
  filteredTradingPairNotifications: ITradePairNotification[] = [];
  filterString: string = '';

  constructor(private tradeService: TradeService) { }

  ngOnInit(): void {
    combineLatest([
      this.selectedTradingPairs$,
      this.tradeService.getUserTradingPairSubscriptionInfo()
    ]).pipe(
      map(([tradingPairs, notifications]) => {
        this.tradingPairNotifications = notifications.filter(notification =>
          !tradingPairs.some(pair => pair.id === notification.tradingPairID)
        );
        this.filteredTradingPairNotifications = [...this.tradingPairNotifications];
      }),
      untilDestroyed(this),
    ).subscribe();
    this.subscribeToWatchedTradingPairs();
  }

  private subscribeToWatchedTradingPairs(): void {
    this.tradeService
      .getWatchedTradingPairs()
      .pipe(untilDestroyed(this))
      .subscribe((pairs) => {
        let tempPairs = JSON.parse(JSON.stringify(pairs));

        this.tradePairs = tempPairs;
      });
  }

  filterNotifications(category: string): void {
    if (category === 'All') {
      this.filteredTradingPairNotifications = [...this.tradingPairNotifications];
      this.filterString = '';
    } else {
      this.filteredTradingPairNotifications = this.tradingPairNotifications.filter(
        notification => {
          const tradingPair = this.getTradingPairById(notification.tradingPairID);
          this.filterString = category;
          return tradingPair && tradingPair.category === category;
        }
      );
    }
  }
  
  private getTradingPairById(id: number): ITradePair | undefined {
    // Return the matching trading pair or undefined if not found
    return this.tradePairs.find(pair => pair.id === id);
  }
}
