import {
  AfterViewInit,
  Component,
  ElementRef,
  OnInit,
  ViewChild,
} from '@angular/core';
import { ITradePair } from '../../models/trade-pair.model';
import { Store } from '@ngxs/store';
import { UpdateSelectedTradingPairs } from '../../store/trade.actions';
import { TradeService } from '../../services/trade.service';
import { UntilDestroy, untilDestroyed } from '@ngneat/until-destroy';
import { TradeState } from '../../store/trade.store';

@UntilDestroy()
@Component({
  selector: 'app-filter',
  templateUrl: './filter.component.html',
  styleUrls: ['./filter.component.scss'],
})
export class FilterComponent implements OnInit, AfterViewInit {
  @ViewChild('list') list!: ElementRef<HTMLDivElement>;
  tradePairs: ITradePair[] = [];
  private watchedTradingPairs: ITradePair[] = [];
  filterString: string = '';
  searchFilterString: string ='';
  tradingPairCount:number = 0;

  constructor(private store: Store, private tradeService: TradeService) { }

  ngOnInit(): void {
    this.subscribeToWatchedTradingPairs();
  }

  ngAfterViewInit(): void {
    this.allowListHorizontalScroll();
  }

  private subscribeToWatchedTradingPairs(): void {
    this.tradeService
      .getWatchedTradingPairs()
      .pipe(untilDestroyed(this))
      .subscribe((pairs) => {
        this.watchedTradingPairs = JSON.parse(JSON.stringify(pairs));
        let tempPairs = JSON.parse(JSON.stringify(pairs));
        let selectedPairs = this.store.selectSnapshot(TradeState.selectedTradingPairs);

        tempPairs.forEach((p: ITradePair) => {
          if (selectedPairs.some((selectedPair) => selectedPair.name === p.name)) {
            p.active = false;
          }
        });

        this.tradePairs = tempPairs;
      });
  }

  private allowListHorizontalScroll(): void {
    this.list.nativeElement.addEventListener('wheel', (e) => {
      e.preventDefault();
      this.list.nativeElement.scrollLeft += e.deltaY;
    });
  }

  toggle(pair: ITradePair): void {
    this.tradePairs = this.tradePairs.map((p) => {
      p = JSON.parse(JSON.stringify(p));
      if (p.id === pair.id) {
        p.active = !p.active;
      }
      return p;
    });
    
    this.tradingPairCount = 0;

    this.tradePairs.forEach((item) => {
      if (item.active === false) {
        this.tradingPairCount += 1;
      }
    });
    
    if (this.tradingPairCount == this.tradePairs.length) {
      this.filterListBtn('');
    } else {
      this.store.dispatch(
        new UpdateSelectedTradingPairs(this.tradePairs.filter((p) => !p.active))
      );
    }
  }

  filterList(value: string): void {
    this.searchFilterString = value;
    this.updateSelectedTradingPairs();
  }

  filterListBtn(value: string): void {
    this.filterString = value;

    if (value === '') {
      // If the 'All' button is clicked, reset the filter and show all trade pairs
      this.tradePairs = this.watchedTradingPairs;
    } else {
      // Filter the trade pairs based on the selected category
      this.tradePairs = this.watchedTradingPairs.filter(pair =>
        pair.category.toLowerCase() === this.filterString.toLowerCase()
      );
    }
    
    this.updateSelectedTradingPairs();
  }

  private updateSelectedTradingPairs(): void {
    if (this.filterString != '') {
      this.tradePairs = this.watchedTradingPairs;
      const filteredPairs = this.tradePairs.map((p) => {
        p = JSON.parse(JSON.stringify(p));
          if (p.category.toLocaleLowerCase().includes(this.filterString.toLocaleLowerCase())) {
            p.active = !p.active;
          }
        return p;
      });

      this.store.dispatch(new UpdateSelectedTradingPairs(filteredPairs.filter((p) => !p.active)));
    } else {
        const filteredPairs = this.tradePairs
          .filter((pair) => pair.active)
          .filter((pair) =>
            pair.name.toLowerCase().includes(this.filterString.toLowerCase())
        );
        this.store.dispatch(new UpdateSelectedTradingPairs(filteredPairs));
    }
  }
}
