import { NgModule } from '@angular/core';
import { RouterModule, Routes } from '@angular/router';
import { SignedOut } from './auth/guards/signed-out';
import { AuthGuard } from './auth/guards/auth.guard';

const routes: Routes = [
  {
    path: '',
    loadChildren: () =>
      import('./auth/auth-routing.module').then((m) => m.AuthRoutingModule),
  },
  {
    path: 'registration',
    loadChildren: () =>
      import('./registration/registration-routing.module').then((m) => m.RegistrationRoutingModule),
    canActivate: [SignedOut]
  },
  {
    path: 'trade',
    loadChildren: () =>
      import('./trade/trade-routing.module').then((m) => m.TradeRoutingModule),
    canActivate: [AuthGuard]
  },
  {
    path: 'discover',
    loadChildren: () =>
      import('./discovery/discovery-routing.module').then(
        (m) => m.DiscoveryRoutingModule
      ),
    canActivate: [AuthGuard]
  },
  {
    path: 'profile',
    loadChildren: () =>
      import('./profile/profile-routing.module').then(
        (m) => m.ProfileRoutingModule
      ),
    canActivate: [AuthGuard]
  },
  {
    path: 'redirect', loadChildren: () => import('./redirect/redirect.module').then(m => m.RedirectModule),
  }
];

@NgModule({
  imports: [RouterModule.forRoot(routes)],
  exports: [RouterModule],
})
export class AppRoutingModule { }
