import { Injectable } from '@angular/core';
import { ITradePair } from '../models/trade-pair.model';
import { Action, Selector, State, StateContext } from '@ngxs/store';
import { UpdateSelectedTradingPairs } from './trade.actions';

export interface ITradeStateModel {
  selectedTradingPairs: ITradePair[];
}

@Injectable()
@State<ITradeStateModel>({
  name: 'trade',
  defaults: {
    selectedTradingPairs: [],
  },
})
export class TradeState {
  @Selector()
  static selectedTradingPairs(state: ITradeStateModel): ITradePair[] {
    return state.selectedTradingPairs;
  }

  @Action(UpdateSelectedTradingPairs) updateSelectedTradingPairs(
    { patchState }: StateContext<ITradeStateModel>,
    { selectedTradingPairs }: UpdateSelectedTradingPairs
  ): void {
    patchState({ selectedTradingPairs });
  }
}
