import { HttpClient, HttpParams } from '@angular/common/http';
import { Injectable } from '@angular/core';
import { Observable, catchError, combineLatest, delay, map, of } from 'rxjs';
import { IAPIResponse } from 'src/app/shared/models/api-response.model';
import { ITradePair } from 'src/app/trade/models/trade-pair.model';
import { TradeService } from 'src/app/trade/services/trade.service';
import { environment } from 'src/environments/environment';

@Injectable({
  providedIn: 'root',
})
export class DiscoverService {

  constructor(private http: HttpClient, private tradeService: TradeService) { }

  search(term: string): Observable<ITradePair[]> {
    const endpoint = `${environment.apiUrl}/search_trading_pairs`;
    const params = new HttpParams().set('name', term);

    return this.http.get<IAPIResponse>(endpoint, { params }).pipe(
      map((response: IAPIResponse) => {
        return response.success
          ? response.records.map((record: any) => this.mapRecordToTradePair(record))
          : [];
      }),
      catchError(error => {
        return of([]);
      }),
      delay(600)
    );
  }


  suggestions(): Observable<ITradePair[]> {
    return combineLatest([
      this.http.get<any>(`${environment.apiUrl}/trading_pairs/recommended`),
      this.tradeService.getWatchedTradingPairs()
    ]).pipe(
      delay(600),
      map(([response, watchedPairs]: [IAPIResponse, ITradePair[]]) => {
        const watchedPairIds = watchedPairs.map(pair => pair.id);
        return response.records
          .filter((record: any) => !watchedPairIds.includes(record.trading_pair_id))
          .map((record: any) => (this.mapRecordToTradePair(record)));
      })
    );
  }

  private mapRecordToTradePair(record: any): ITradePair {
    return {
      id: record.trading_pair_id,
      name: record.name,
      unit: record.currency,
      logo: record.icon,
      active: true,
      overview: record.overview,
      staffRecommended: record.staff_recommended,
      externalChartURL: record.external_chart_url,
      category: record.category,
    };
  }
}
