import { Component, OnInit } from '@angular/core';
import { DiscoverService } from '../../services/discover.service';
import { UntilDestroy, untilDestroyed } from '@ngneat/until-destroy';
import { ITradePair } from 'src/app/trade/models/trade-pair.model';
import { ISearchResult } from '../results/results.component';
import { TradeService } from 'src/app/trade/services/trade.service';
import { ITradePairCard } from 'src/app/shared/components/trade-pair-card/trade-pair-card.component';

@UntilDestroy()
@Component({
  selector: 'app-discover',
  templateUrl: './discover.component.html',
  styleUrls: ['./discover.component.scss'],
})
export class DiscoverComponent implements OnInit {
  loading = false;
  searchHasFocus = false;
  searchTerm = '';

  results!: ITradePair[];
  selectedResults: ISearchResult[] = [];

  watchList!: ITradePairCard[];
  suggestions!: ITradePairCard[];
  selectedSuggestions: ITradePairCard[] = [];

  showWatchlist = false;
  showResults = false;

  get selected(): ITradePairCard[] {
    return [...this.selectedResults, ...this.selectedSuggestions];
  }

  constructor(
    private discoverService: DiscoverService,
    private tradeService: TradeService
  ) { }

  ngOnInit(): void {
    this.subscribeToWatchlist();
    this.subscribeToSuggestions();
  }

  private subscribeToWatchlist() {
    this.tradeService
      .getWatchedTradingPairs()
      .pipe(untilDestroyed(this))
      .subscribe((res) => {
        this.watchList = res.map((pair) => ({ ...pair, selected: false }));
      });
  }

  private subscribeToSuggestions() {
    this.discoverService
      .suggestions()
      .pipe(untilDestroyed(this))
      .subscribe((res) => {
        this.suggestions = res.map((pair) => ({ ...pair, selected: false }));
      });
  }

  focus() {
    this.searchHasFocus = true;
  }

  blur() {
    this.searchHasFocus = false;
  }

  search() {
    this.loading = true;
    this.discoverService
      .search(this.searchTerm)
      .pipe(untilDestroyed(this))
      .subscribe((res) => {
        // Filter out trading pairs that are already in the watchlist.
        this.results = res.filter(
          (result) => !this.watchList.some((watchPair) => watchPair.id === result.id)
        );
        this.loading = false;
        this.showResults = true;
        this.showWatchlist = false;

        this.searchTerm = '';
      });
  }


  updateSelected(selected: ISearchResult[]) {
    this.selectedResults = selected;
  }

  onSuggestionCardSelected(card: ITradePairCard) {
    card.selected = !card.selected;
    this.selectedSuggestions = this.suggestions.filter((s) => s.selected);
  }

  addToWatchList() {
    this.tradeService.addToWatchList(this.selected).subscribe(successStatuses => {

      if (this.results) {
        this.results = this.results.map((pair) => ({ ...pair, selected: false }));
      }

      if (this.suggestions) {
        this.suggestions = this.suggestions.map((pair) => ({ ...pair, selected: false }));
      }

      this.selected.forEach((selectedPair, index) => {
        if (successStatuses[index]) {
          // Remove the selected pair from search results

          if (this.results != undefined) {
            this.results = this.results.filter(pair => pair.id !== selectedPair.id);
          }

          // Remove the selected pair from suggestions
          this.suggestions = this.suggestions.filter(pair => pair.id !== selectedPair.id);

          if (!this.watchList.find(pair => pair.id === selectedPair.id)) {
            this.watchList.push({ ...selectedPair, selected: false });
          }
        }
      });

      this.selectedSuggestions = [];
      this.selectedResults = [];
      this.showResults = false;
      this.showWatchlist = true;
    },
      error => {
        console.error('Error:', error);
      });
  }

  toggleWatchlist() {
    this.showWatchlist = !this.showWatchlist;
  }

  removeFromWatchList(pair: ITradePair) {
    this.tradeService.removeFromWatchList(pair).subscribe(success => {
      if (success) {
        // If the API delete was successful, remove from watchList and add to suggestions
        this.watchList = this.watchList.filter(watchPair => watchPair.id !== pair.id);

        // Add to suggestions if not already present
        if (!this.suggestions.find(suggestionPair => suggestionPair.id === pair.id)) {
          this.suggestions.push({ ...pair, selected: false });
        }
      }
    },
      error => {
        console.error('Error:', error);
      });

  }

}
