import { HttpClient } from '@angular/common/http';
import { Injectable } from '@angular/core';
import { AuthService } from '@auth0/auth0-angular';
import { Observable, catchError, combineLatest, map, of } from 'rxjs';
import { environment } from 'src/environments/environment';
import { IAPIResponse } from '../../shared/models/api-response.model';
import { IIndicatorData } from '../models/indicator-data.model';
import { ITradePairNotification } from '../models/trade-pair-subscription-info.model';
import { ITradePair } from '../models/trade-pair.model';

@Injectable({
  providedIn: 'root',
})
export class TradeService {
  constructor(private http: HttpClient) { }

  getTradingPairs(): Observable<ITradePair[]> {
    return this.http.get<IAPIResponse>(`${environment.apiUrl}/trading_pairs`).pipe(
      map((response: IAPIResponse) => {
        return response.records.map((record: any) => {
          return this.mapToTradePair(record)

        });
      }),
      catchError(error => {
        return of([]);
      })
    );
  }

  getRecommendedTradingPairs(): Observable<ITradePair[]> {
    return this.http.get<IAPIResponse>(`${environment.apiUrl}/trading_pairs/recommended`).pipe(
      map((response: IAPIResponse) => {
        return response.records.map((record: any) => {
          return this.mapToTradePair(record)

        });
      }),
      catchError(error => {
        return of([]);
      })
    );
  }

  getRecommendedTradingPairIndicators(): Observable<IIndicatorData[]> {
    return this.http.get<IAPIResponse>(`${environment.apiUrl}/trading_pairs/recommended/indicators`).pipe(
      map((response: IAPIResponse) => {
        return response.records.map((record: any) => {
          return this.mapToIndicatorData(record)
        });
      }),
      catchError(error => {
        return of([]);
      })
    );
  }


  getWatchedTradingPairs(): Observable<ITradePair[]> {
    return this.http.get<IAPIResponse>(`${environment.apiUrl}/user/trading_pairs`).pipe(
      map((response: IAPIResponse) => {
        return response.records.map(record => {
          return this.mapToTradePair(record)
        });
      }),
      catchError(error => of([]))
    );
  }




  addToWatchList(pairs: ITradePair[]): Observable<boolean[]> {
    let sources = pairs.map(pair =>
      this.http.post<IAPIResponse>(`${environment.apiUrl}/user/trading_pairs/${pair.id}`, {})
    );

    return combineLatest(sources).pipe(
      map(allResults => {
        return allResults.map(response => response.success === true);
      })
    );
  }


  removeFromWatchList(pair: ITradePair): Observable<boolean> {
    return this.http.delete<IAPIResponse>(`${environment.apiUrl}/user/trading_pairs/${pair.id}`, {})
      .pipe(
        map(response => {
          return response.success === true;
        })
      );
  }


  getIndicatorData(): Observable<IIndicatorData[]> {
    return this.http.get<IAPIResponse>(`${environment.apiUrl}/user/indicators`).pipe(
      map(response => response.records.map(record => ({
        tradingPair: record.trading_pair,
        leverage: record.leverage,
        action: record.action,
        entryPrice: record.entry_price,
        exitPrice: record.exit_price,
        imgSrc: record.img_src,
        time: new Date(record.time)
      }))),
      catchError(error => of([]))
    );
  }

  getUserTradingPairSubscriptionInfo(): Observable<ITradePairNotification[]> {
    return this.http.get<IAPIResponse>(`${environment.apiUrl}/user/trading_pairs_subscriptions`).pipe(
      map((response: IAPIResponse) => {
        return response.records.map((record: any) => {
          const tradePairNotification: ITradePairNotification = {
            tradingPairID: record.trading_pair_id,
            tradingPairName: record.trading_pair_name,
            icon: record.icon,
            notifications: record.notifications,
            tradingType: record.trading_type as 'Short' | 'Long' | 'Short/Long',
            expanded: false
          };
          return tradePairNotification;
        });
      }),
      catchError(error => {
        return of([]);
      })
    );
  }

  updateTradingPairNotification(tradingPair: ITradePairNotification): Observable<boolean> {
    return this.http.put<IAPIResponse>(`${environment.apiUrl}/user/trading_pairs/${tradingPair.tradingPairID}`, {
      notifications: tradingPair.notifications,
      trading_type: tradingPair.tradingType,
      trading_pair_id: tradingPair.tradingPairID,
    }).pipe(
      map(response => response.success === true),
      catchError(error => of(false))
    );
  }

  private mapToIndicatorData(record: any): IIndicatorData {
    return {
      tradingPair: record.trading_pair,
      leverage: record.leverage,
      action: record.action as 'Short' | 'Long',
      entryPrice: record.entry_price,
      exitPrice: record.exit_price,
      time: new Date(record.time),
      imgSrc: record.img_src
    };
  }

  private mapToTradePair(record: any): ITradePair {
    return {
      id: record.trading_pair_id,
      name: record.name,
      unit: record.currency,
      logo: record.icon,
      active: false,
      overview: record.overview,
      staffRecommended: record.staff_recommended,
      externalChartURL: record.external_chart_url,
      category: record.category,
    }
  }


}
