import { Component, OnInit } from '@angular/core';
import {
  trigger,
  state,
  style,
  transition,
  animate,
} from '@angular/animations';
import { IIndicatorData } from '../../models/indicator-data.model';
import { TradeService } from '../../services/trade.service';
import { TradeState } from '../../store/trade.store';
import { Store } from '@ngxs/store';

@Component({
  selector: 'app-indicators',
  templateUrl: './indicators.component.html',
  styleUrls: ['./indicators.component.scss'],
})

export class IndicatorsComponent implements OnInit {

  indicators: IIndicatorData[] = [];

  constructor(private tradeService: TradeService, private store: Store) { }

  ngOnInit() {
    this.tradeService.getIndicatorData().subscribe(data => {
      this.store.select(TradeState.selectedTradingPairs).subscribe(selectedTradingPairs => {
        this.indicators = data.filter(i =>
          !selectedTradingPairs.some(tradePair => tradePair.name === i.tradingPair));

        // Update indicators array, and the filtered indicators
        this.updateIndicators();
      });
    });
  }

  showComingUp = false;
  showToday = true;
  showHistory = false;

  comingUpIndicators: IIndicatorData[] = [];
  todayIndicators: IIndicatorData[] = [];
  historyIndicators: IIndicatorData[] = [];


  updateIndicators(): void {
    const now = new Date();
    this.comingUpIndicators = this.indicators.filter(i => {
      const sameDate = i.time.getDate() === now.getDate() && i.time.getMonth() === now.getMonth() && i.time.getFullYear() === now.getFullYear();
      return !sameDate && i.time > now;
    });

    this.todayIndicators = this.indicators.filter(i => {
      const sameDate = i.time.getDate() === now.getDate() && i.time.getMonth() === now.getMonth() && i.time.getFullYear() === now.getFullYear();
      return sameDate;
    });

    this.historyIndicators = this.indicators.filter(i => {
      const sameDate = i.time.getDate() === now.getDate() && i.time.getMonth() === now.getMonth() && i.time.getFullYear() === now.getFullYear();
      return i.time < now && !sameDate;
    });
  }

  toggleSection(section: string): void {
    if (section === 'comingUp') {
      this.showComingUp = true;
      this.showToday = false;
      this.showHistory = false;
    } else if (section === 'today') {
      this.showComingUp = false;
      this.showToday = true;
      this.showHistory = false;
    } else if (section === 'history') {
      this.showComingUp = false;
      this.showToday = false;
      this.showHistory = true;
    }
  }

}