import { Component, HostBinding } from '@angular/core';
import {
  trigger,
  state,
  style,
  transition,
  animate,
} from '@angular/animations';
import { TradeService } from 'src/app/trade/services/trade.service';
import { IIndicatorData } from 'src/app/trade/models/indicator-data.model';
import { RegistrationState } from '../../store/registration.state';
import { Store, Select } from '@ngxs/store';
import { Observable } from 'rxjs';
import { ITradePair } from 'src/app/trade/models/trade-pair.model';
import { isToday, isPast } from 'date-fns';
import { UntilDestroy, untilDestroyed } from '@ngneat/until-destroy';

@UntilDestroy()
@Component({
  selector: 'app-signup-discover',
  templateUrl: './signup-discover.component.html',
  styleUrls: ['./signup-discover.component.scss'],
  animations: [
    trigger('rotate', [
      state(
        'down',
        style({
          transform: 'rotate(0)',
        })
      ),
      state(
        'right',
        style({
          transform: 'rotate(-90deg)',
        })
      ),
      transition('down <=> right', [animate('0.3s ease-out')]),
    ]),
  ],
})
export class SignupDiscoverComponent {
  @HostBinding('class') layoutCls = 'registration-layout';
  @Select(RegistrationState.selectedTradingPairs) selectedPairs$!: Observable<ITradePair[]>;
  now = new Date();
  comingUpTime = new Date(this.now.getTime() + 24 * 60 * 60 * 1000);
  comingUpIndicators: IIndicatorData[] = [];
  todayIndicators: IIndicatorData[] = [];
  historyIndicators: IIndicatorData[] = [];
  showComingUp = false;
  showToday = true;
  showHistory = false;
  data = {
    tradingPair: 'ETH/USDT',
    leverage: 1,
    action: 'short' as 'short' | 'long',
    entryPrice: 4800,
    exitPrice: 4100,
    time: this.comingUpTime,
    imgSrc:
      'https://upload.wikimedia.org/wikipedia/commons/thumb/4/46/Bitcoin.svg/2048px-Bitcoin.svg.png',
  };

  constructor(private tradeService: TradeService) {
  }

  ngOnInit(): void {
    let selectedPairs: ITradePair[];

    this.selectedPairs$.pipe(untilDestroyed(this)).subscribe(pairs => {
      selectedPairs = pairs;
    });

    this.tradeService.getRecommendedTradingPairIndicators()
      .pipe(untilDestroyed(this))
      .subscribe(indicators => {
        indicators.forEach(indicator => {
          const indicatorDate = new Date(indicator.time);
          if (selectedPairs.some(pair => pair.name === indicator.tradingPair)) {
            if (isToday(indicatorDate)) {
              this.todayIndicators.push(indicator);
            } else if (isPast(indicatorDate)) {
              this.historyIndicators.push(indicator);
            } else {
              this.comingUpIndicators.push(indicator);
            }
          }
        });
      });
  }


  ngOnDestroy(): void {

  }

  toggleSection(section: string): void {
    if (section === 'comingUp') {
      this.showComingUp = true;
      this.showToday = false;
      this.showHistory = false;
    } else if (section === 'today') {
      this.showComingUp = false;
      this.showToday = true;
      this.showHistory = false;
    } else if (section === 'history') {
      this.showComingUp = false;
      this.showToday = false;
      this.showHistory = true;
    }
  }
}
