import { Injectable } from '@angular/core';
import {
  ActivatedRouteSnapshot,
  CanActivate,
  Router,
  RouterStateSnapshot,
  UrlTree,
} from '@angular/router';
import { Observable } from 'rxjs';
import { SignupService } from '../services/signup.service';
import { Select, Store } from '@ngxs/store';
import { RegistrationState } from '../store/registration.state';
import { ITradePair } from 'src/app/trade/models/trade-pair.model';

@Injectable({
  providedIn: 'root',
})
export class TradingPairsSelectedGuard implements CanActivate {
  @Select(RegistrationState.selectedTradingPairs)
  selectedTradingPairs$!: Observable<ITradePair[]>;
  atLeastOneTradingPairSelected = false;

  constructor(
    private router: Router,
    private selectedTradingPairsService: SignupService,
    store: Store
  ) {
    this.selectedTradingPairs$.subscribe((selectedTradingPairs) => {
      this.atLeastOneTradingPairSelected =
        selectedTradingPairs.length > 0 ? true : false;
    });
  }
  canActivate(
    route: ActivatedRouteSnapshot,
    state: RouterStateSnapshot
  ):
    | Observable<boolean | UrlTree>
    | Promise<boolean | UrlTree>
    | boolean
    | UrlTree {
    return this.atLeastOneTradingPairSelected;
  }
}
