import { Injectable, OnDestroy } from '@angular/core';
import { BehaviorSubject, Subject, of, firstValueFrom } from 'rxjs';
import { takeUntil } from 'rxjs/operators';
import { AuthService } from '@auth0/auth0-angular';
import { CookieService } from 'ngx-cookie-service';
@Injectable({

    providedIn: 'root'

})
export class CookieExtensionService implements OnDestroy {
    private destroy$ = new Subject<void>();
    public shouldDisplayCookies$: BehaviorSubject<boolean>;

    constructor(private authService: AuthService, private cookies: CookieService) {
        this.shouldDisplayCookies$ = new BehaviorSubject<boolean>(this.shouldDisplayCookieConsent());
        this.authService.isAuthenticated$
            .pipe(takeUntil(this.destroy$))
            .subscribe(isLoggedIn => {
                if (isLoggedIn && !this.hasConsent()) {
                    this.authService.logout();
                    this.shouldDisplayCookies$.next(true);
                }
            });
    }

    ngOnDestroy(): void {
        this.destroy$.next();
        this.destroy$.complete();
    }

    private shouldDisplayCookieConsent(): boolean {
        return !this.cookies.check('cookieConsent');

    }

    private hasConsent(): boolean {
        return this.cookies.get('cookieConsent') !== 'false';
    }

    checkCookies(): boolean {
        if (!this.hasConsent()) {
            this.shouldDisplayCookies$.next(true);
            return false;
        }
        return true;
    }

    accept(): void {
        this.cookies.set('cookieConsent', 'true');
        this.shouldDisplayCookies$.next(false);
    }

    async decline(): Promise<void> {
        this.cookies.set('cookieConsent', 'false');
        this.shouldDisplayCookies$.next(false);
        const isLoggedIn = await firstValueFrom(this.authService.isAuthenticated$);
        if (isLoggedIn) {
            this.authService.logout();
        }
    }

}