import { Injectable } from '@angular/core';
import { IUser } from '../models/user.model';
import { Action, Selector, State, StateContext } from '@ngxs/store';
import { UpdateUser, UpdateUserRiskAppetiteScore } from './user.actions';

export interface IUserStateModel {
    user: IUser;
}

@Injectable()
@State<IUserStateModel>({
    name: 'user',
    defaults: {
        user: {
            riskAppetiteScore: 5,
            enableNotifications: true,
        },
    },
})
export class UserState {
    @Selector()
    static user(state: IUserStateModel): IUser {
        return state.user;
    }

    @Action(UpdateUser)
    updateUser({ patchState }: StateContext<IUserStateModel>, { user }: UpdateUser): void {
        patchState({ user });
    }

    @Action(UpdateUserRiskAppetiteScore)
    updateUserRiskAppetiteScore({ getState, patchState }: StateContext<IUserStateModel>, { score }: UpdateUserRiskAppetiteScore): void {
        const state = getState();
        patchState({
            user: {
                ...state.user,
                riskAppetiteScore: score,
            },
        });
    }
}
