import {
  Component,
  EventEmitter,
  HostBinding,
  HostListener,
  Input,
  Output,
} from '@angular/core';
import { ITradePair } from 'src/app/trade/models/trade-pair.model';

export interface ITradePairCard extends ITradePair {
  selected: boolean;
}

@Component({
  selector: 'app-trade-pair-card',
  templateUrl: './trade-pair-card.component.html',
  styleUrls: ['./trade-pair-card.component.scss'],
})
export class TradePairCardComponent {
  @HostBinding('class.selected') get isSelected(): boolean {
    return this.card.selected;
  }
  @Input() card!: ITradePairCard;
  @Output() selected: EventEmitter<ITradePairCard> = new EventEmitter();
  @HostListener('click') onClick(): void {
    this.selected.emit(this.card);
  }
}
